833	  \label{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen_curve}
834	  \lean{AlgebraicGeometry.Scheme.hasAffineCechAcyclicCover_of_basicOpen_curve}
835	  \uses{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen}
836	  Same statement specialised to the structure sheaf $\mathcal O_C$.
837	\end{theorem}
838	
839	\begin{proof}
840	  Direct application.
841	\end{proof}
